// Текстовое ДЗ (без файлов) - подготовка messages content
const hwText = $input.item.json.hw_text || $('Edit Fields').item.json.hw_text || '[Текст отсутствует]';
const studentName = $('Edit Fields').item.json.student_name || 'Студент';
const lessonDesc = $('Edit Fields').item.json.lesson_desc || 'Оценить ДЗ';

console.log(`📝 Текстовое ДЗ от ${studentName}`);

// Формируем messages content только с текстом
const messagesContent = [
  {
    type: "text",
    text: `РАБОТА СТУДЕНТА:\n${hwText}`
  }
];

return [{
  json: {
    ...$input.item.json,
    messages_content: messagesContent
  }
}];

// Проверка типа файла и маршрутизация
const binaryData = $input.item.json.binary?.data;
const mimeType = binaryData?.mimeType || $input.item.json.mimeType || '';
const fileType = mimeType.split('/')[0];

let output = 0; // 0 = text/no file, 1 = image, 2 = audio, 3 = video

if (mimeType.startsWith('image')) {
  output = 1;
} else if (mimeType.startsWith('audio')) {
  output = 2;
} else if (mimeType.startsWith('video')) {
  output = 3;
}

return [{
  json: {
    ...$input.item.json,
    file_type: fileType,
    mime_type: mimeType,
    route_output: output
  },
  binary: $input.item.json.binary  // ← Сохраняем binary!
}];

// Ветка ФОТО: конвертация в Base64
const binaryData = $input.first().binary?.data;

if (!binaryData) {
  throw new Error('Нет бинарных данных');
}

const mimeType = binaryData.mimeType || 'image/jpeg';
const fileSize = binaryData.data?.length || 0;

console.log(`📸 Фото: ${fileSize} байт, MIME: ${mimeType}`);

$input.first().json.base64_image = binaryData.data;
$input.first().json.mime_type = mimeType;
$input.first().json.file_size = fileSize;
$input.first().json.file_type = 'image';

return $input.all();

// Ветка АУДИО: проверка размера + сохранение данных
const binaryData = $input.first().binary?.data;

if (!binaryData) {
  throw new Error('Нет бинарных данных');
}

const mimeType = binaryData.mimeType || 'audio/ogg';
const fileSize = binaryData.data?.length || 0;
const MAX_AUDIO_SIZE = 10 * 1024 * 1024; // 10 МБ

console.log(`🎧 Аудио: ${fileSize} байт (${(fileSize / 1024 / 1024).toFixed(2)} МБ), MIME: ${mimeType}`);

if (fileSize > MAX_AUDIO_SIZE) {
  console.log(`⚠️ Аудио больше 10 МБ!`);
  $input.first().json.audio_truncated = true;
  $input.first().json.audio_warning = `Аудио слишком большое (${(fileSize / 1024 / 1024).toFixed(2)} МБ). ИИ обработает только часть.`;
} else {
  $input.first().json.audio_truncated = false;
}

// Сохраняем binary data для отправки в OpenRouter
$input.first().json.audio_data = binaryData.data;
$input.first().json.file_size = fileSize;
$input.first().json.file_type = 'audio';
$input.first().json.mime_type = mimeType;

return $input.all();

// Ветка ВИДЕО (кружочки/голосовые video/ogg): проверка + сохранение данных
const binaryData = $input.first().binary?.data;

if (!binaryData) {
  throw new Error('Нет бинарных данных');
}

const mimeType = binaryData.mimeType || 'video/ogg';
const fileSize = binaryData.data?.length || 0;
const MAX_SIZE = 10 * 1024 * 1024; // 10 МБ

console.log(`🎥 Видео/кружочек: ${fileSize} байт (${(fileSize / 1024 / 1024).toFixed(2)} МБ), MIME: ${mimeType}`);

if (fileSize > MAX_SIZE) {
  console.log(`⚠️ Видео больше 10 МБ!`);
  $input.first().json.file_truncated = true;
  $input.first().json.file_warning = `Файл слишком большой (${(fileSize / 1024 / 1024).toFixed(2)} МБ).`;
} else {
  $input.first().json.file_truncated = false;
}

// Сохраняем binary data для отправки в OpenRouter
$input.first().json.audio_data = binaryData.data; // Gemini принимает аудио из видео как audio_data
$input.first().json.file_size = fileSize;
$input.first().json.file_type = 'video';
$input.first().json.mime_type = mimeType;

return $input.all();

// Подготовка messages content для OpenRouter AI
const hwText = $input.item.json.hw_text || $('Edit Fields').item.json.hw_text || '[Текст отсутствует]';
const audioWarning = $input.item.json.audio_warning || '';
const fileWarning = $input.item.json.file_warning || '';
const base64Image = $input.item.json.base64_image || null;
const mimeType = $input.item.json.mime_type || '';
const fileType = $input.item.json.file_type || '';
const audioData = $input.item.json.audio_data || null;

// Формируем text content
let textContent = `РАБОТА СТУДЕНТА:\n${hwText}`;
if (audioWarning) textContent += `\n\n⚠️ ${audioWarning}`;
if (fileWarning) textContent += `\n\n⚠️ ${fileWarning}`;

// Формируем messages content array
const messagesContent = [
  {
    type: "text",
    text: textContent
  }
];

// Добавляем image если есть
if (base64Image && mimeType) {
  messagesContent.push({
    type: "image_url",
    image_url: {
      url: `data:${mimeType};base64,${base64Image}`
    }
  });
}

// Добавляем audio если есть (для audio и video)
if (audioData && (fileType === 'audio' || fileType === 'video')) {
  const audioFormat = mimeType.includes('ogg') ? 'ogg' : 'wav';
  messagesContent.push({
    type: "input_audio",
    input_audio: {
      data: audioData,
      format: audioFormat
    }
  });
}

console.log('📝 Messages content prepared:', JSON.stringify(messagesContent).substring(0, 200));

return [{
  json: {
    ...$input.item.json,
    messages_content: messagesContent
  }
}];

// Подготовка JSON для OpenRouter AI
const studentName = $('Edit Fields').item.json.student_name || 'Студент';
const lessonDesc = $('Edit Fields').item.json.lesson_desc || 'Оценить ДЗ';
const messagesContent = $input.item.json.messages_content || [];

console.log(`🤖 Подготовка запроса к ИИ для ${studentName}`);

return [{
  json: {
    openrouter_request: {
      model: 'google/gemini-2.5-flash',
      response_format: { type: 'json_object' },
      messages: [
        {
          role: 'system',
          content: `Ты мудрый наставник на онлайн-курсе. Имя студента: ${studentName}.\n\nКонтекст задания:\n${lessonDesc}\n\nТВОИ ПРАВИЛА:\n1. Оцени работу. Если есть фото — посмотри, соответствует ли оно заданию.\n2. Если есть аудио/видео — ИИ может напрямую воспринимать аудио.\n3. Если работа осмысленная — ставь "is_approved": true. Бессмысленная — false.\n4. Твой "feedback_text" должен быть личным, ободряющим, с правильными окончаниями.\n5. Если студент прислал фото — упомяни конкретные детали.\n\nОтвет СТРОГО в формате JSON: {"is_approved": boolean, "feedback_text": "string"}`
        },
        {
          role: 'user',
          content: messagesContent
        }
      ]
    }
  }
}];

// Парсинг ответа от OpenRouter
try {
  const rawResponse = $input.item.json.choices[0].message.content;

  console.log('🤔 Сырой ответ ИИ:', rawResponse.substring(0, 200));

  const jsonMatch = rawResponse.match(/(\{[\s\S]*\})/);

  if (!jsonMatch || !jsonMatch[1]) {
    throw new Error('Не удалось извлечь JSON из ответа ИИ');
  }

  const parsedData = JSON.parse(jsonMatch[1]);

  if (typeof parsedData.is_approved !== 'boolean') {
    throw new Error('is_approved должен быть boolean');
  }

  if (typeof parsedData.feedback_text !== 'string') {
    throw new Error('feedback_text должен быть string');
  }

  return {
    json: {
      is_approved: parsedData.is_approved,
      feedback_text: parsedData.feedback_text,
      ai_raw_response: rawResponse
    }
  };
} catch (error) {
  console.error('❌ Ошибка парсинга:', error.message);

  return {
    json: {
      is_approved: true,
      feedback_text: `⚠️ Возникла техническая проблема при анализе ИИ, поэтому задание одобрено автоматически. Спасибо за понимание!\n\n(Ошибка: ${error.message})`,
      ai_raw_response: $input.item.json.choices?.[0]?.message?.content || 'Нет ответа',
      parse_error: true
    }
  };
}
